def can_arrange(arr):
    num_swaps, largest_index, swap_with, inversions = 0, -1, -1, 0
    for i in range(len(arr) - 1, 0, -1):
        if arr[i] < arr[i-1]:
            largest_index = i - 1
            swap_with = i
            num_swaps += 1
            inversions += 1

