    accounts: Arc<Mutex<Vec<Account>>>,
}

impl Bank {
    fn new() -> Bank {
        Bank {
            accounts: Arc::new(Mutex::new(Vec::new())),
        }
    }

    fn new_account(&self, initial_balance: i32) {
        let mut accounts = self.accounts.lock().unwrap();
        accounts.push(Account::new(initial_balance));
    }

    fn deposit(&self, account_index: usize, amount: i32) {
        let mut accounts = self.accounts.lock().unwrap();
        if let Some(account) = accounts.get_mut(account_index) {
            account.deposit(amount);
        }
    }

    fn withdraw(&self, account_index: usize, amount: i32) -> Result<(), &'static str> {
        let mut accounts = self.accounts.lock().unwrap();
        if let Some(account) = accounts.get_mut(account_index) {
            account.withdraw(amount)
        } else {
            Err("Account not found")
        }
    }

    fn get_balance(&self, account_index: usize) -> Option<i32> {
        let accounts = self.accounts.lock().unwrap();
        if let Some(account) = accounts.get(account_index) {
            Some(account.get_balance())
        } else {
            None
        }
    }
}

