    bank.new_account(100);

    let bank_ref = Arc::new(bank);
    let bank_ref_clone = Arc::clone(&bank_ref);

    let deposit_thread = thread::spawn(move || {
        bank_ref.deposit(0, 50);
    });

    let withdraw_thread = thread::spawn(move || {
        let result = bank_ref_clone.withdraw(0, 30);
        if let Err(err) = result {
            println!("Withdrawal failed: {}", err);
        }
    });

    deposit_thread.join().unwrap();
    withdraw_thread.join().unwrap();

    println!("Final balance: {:?}", bank_ref.get_balance(0));
}
