class NewtonSolver:
    TOL = 0.0000001  # tolerance
    ITERLIMIT = 1000  # iteration limit
    CLOSE_RUNS = 10  # after getting close, do more passes

    def __init__(self):
        self._args = {}

    def set_argument(self, arg, value):
        if arg not in self._args:
            raise ValueError(f"Argument '{arg}' not in _args")
        setattr(self, arg, value)

    def _solve_for(self, arg):
        '''Newton's method solver'''
        args = self._args
        if arg not in args:
            raise ValueError(f"Argument '{arg}' not in _args")
        x0 = args[arg] if args[arg] else 1
        if x0 == 0:
            # Handle the case when the initial guess is 0
            raise ValueError("Initial guess cannot be 0")
        f = lambda x:  # Define the function for which to find the root
        f_prime = lambda x:  # Define the derivative of the function
        runs = 0
        while runs < self.ITERLIMIT:
            x1 = x0 - f(x0) / f_prime(x0)  # Newton's method iteration
            if abs(x1 - x0) < self.TOL:
                return x1  # Return the approximate root
            x0 = x1
            runs += 1
        raise ValueError("Newton's method did not converge within the iteration limit")
