In RSA algorithm, public key and private key are generated based on some mathematical concepts like Euler's totient function and creating the modular multiplicative inverse. Here is the code for generating the key pairs:

```python
import random
from sympy import mod_inverse

def is_prime(num):
    if num <= 1:
        return False
    elif num == 2:
        return True
    else:
        for i in range(2, num):
            if (num % i) == 0:
                return False
        return True

def gcd(x, y):
    while(y):
        x, y = y, x % y
    return x

def generate_keypair(p, q):
    if not (is_prime(p) and is_prime(q)):
        raise ValueError('Both numbers must be prime.')
    elif p == q:
        raise ValueError('p and q cannot be equal')

    n = p * q
    print('n = ',n)

    phi = (p-1) * (q-1)
    print('phi = ',phi)

    e = random.randrange(1, phi)

    g = gcd(e, phi)
    while g != 1:
        e = random.randrange(1, phi)
        g = gcd(e, phi)

    d = mod_inverse(e, phi)

    return ((e, n), (d, n))

p = 17
q = 11

public, private = generate_keypair(p, q)
print("Public Key: ",public)
print("Private Key: ",private)
```

