import math
import random
import multiprocessing

def is_prime(n, cache={}):
    if n in cache:
        return cache[n]
    if n < 2:
        cache[n] = False
        return False
    for i in range(2, int(math.sqrt(n)) + 1):
        if n % i == 0:
            cache[n] = False
            return False
    cache[n] = True
    return True

def miller_rabin(n, base):
    if pow(base, n-1, n) != 1:
        return False
    d = n - 1
    while d % 2 == 0:
        d //= 2
        x = pow(base, d, n)
        if x == 1 or x == n - 1:
            return True
    return False

def is_prime_miller_rabin(n):
    if n < 2:
        return False
    if n in {2, 3}:
        return True
    if n % 2 == 0:
        return False
    for _ in range(20):  # Adjust the number of iterations for desired accuracy
        base = random.randint(2, n - 1)
        if not miller_rabin(n, base):
            return False
    return True

def find_primes(lower, upper):
    if lower >= upper:
        raise ValueError("Invalid range: lower bound must be less than upper bound")
    pool = multiprocessing.Pool()
    primes = pool.map(is_prime_miller_rabin, range(lower, upper + 1))
    pool.close()
    pool.join()
    return [i for i, prime in zip(range(lower, upper + 1), primes) if prime]

