public class FibonacciEvenNumbers {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        // Prompt the user to enter the lower and upper limits for the range
        System.out.print("Enter the lower limit: ");
        int lowerLimit = scanner.nextInt();

        System.out.print("Enter the upper limit: ");
        int upperLimit = scanner.nextInt();

        // Validate the input
        while (lowerLimit > upperLimit) {
            System.out.println("Error: The lower limit must be less than or equal to the upper limit.");
            System.out.print("Enter the lower limit: ");
            lowerLimit = scanner.nextInt();

            System.out.print("Enter the upper limit: ");
            upperLimit = scanner.nextInt();
        }

        scanner.close();

        List<Integer> evenNumbers = generateEvenNumbers(lowerLimit, upperLimit);

        System.out.println("Generated even numbers: " + evenNumbers);

        int n = evenNumbers.size();

        List<BigInteger> fibonacciNumbers = calculateFibonacciNumbers(n);

        System.out.println("Fibonacci numbers: " + fibonacciNumbers);

        List<BigInteger> factorials = calculateFactorials(fibonacciNumbers);

        System.out.println("Factorials: " + factorials);
    }

    // Generate a random range of even numbers between the lower and upper limits
    public static List<Integer> generateEvenNumbers(int lowerLimit, int upperLimit) {
        List<Integer> evenNumbers = new ArrayList<>();
        Random random = new Random();

        for (int i = lowerLimit; i <= upperLimit; i++) {
            if (i % 2 == 0) {
                evenNumbers.add(i);
            }
        }

        return evenNumbers;
    }

    // Calculate the Nth term of the Fibonacci sequence
    public static List<BigInteger> calculateFibonacciNumbers(int n) {
        List<BigInteger> fibonacciNumbers = new ArrayList<>();
        BigInteger a = BigInteger.ZERO;
        BigInteger b = BigInteger.ONE;

        for (int i = 0; i < n; i++) {
            fibonacciNumbers.add(a);
            BigInteger next = a.add(b);
            a = b;
            b = next;
        }

        return fibonacciNumbers;
    }

    // Calculate the factorial of each Fibonacci number up to the Nth term
    public static List<BigInteger> calculateFactorials(List<BigInteger> fibonacciNumbers) {
        List<BigInteger> factorials = new ArrayList<>();

        for (BigInteger number : fibonacciNumbers) {
            BigInteger factorial = BigInteger.ONE;

            for (BigInteger i = BigInteger.ONE; i.compareTo(number) <= 0; i = i.add(BigInteger.ONE)) {
                factorial = factorial.multiply(i);
            }

            factorials.add(factorial);
        }

        return factorials;
    }
}

