import java.util.*;

public class Library {
    HashMap<String, String> bookAuthorMap;
    TreeMap<String, ArrayList<String>> authorBooksMap;

    public Library() {
        bookAuthorMap = new HashMap<>();
        authorBooksMap = new TreeMap<>();
    }

    public void addBook(String title, String author) {
        // Check if author already exists in the authorBooksMap
        // If yes, just add the new title to the existing ArrayList
        // If not, create a new ArrayList, add the title, and put it into authorBooksMap
        if (authorBooksMap.containsKey(author)){
            authorBooksMap.get(author).add(title);
        }
        else{
            ArrayList<String> books = new ArrayList<>();
            books.add(title);
            authorBooksMap.put(author, books);
        }

        // Add the book & match to its author
        bookAuthorMap.put(title, author);
    }

    public String getAuthor(String title) {
        return bookAuthorMap.get(title);
    }

    public List<String> getBooks(String author) {
        return authorBooksMap.get(author);
    }
}
