To reverse a singly linked list using only recursion and without using any additional data structures, you can follow these steps in C++:

1. Define a recursive function `reverseList` that takes a pointer to the head of the linked list as a parameter.

2. Base case: If the head is NULL or the list has only one element (i.e., head->next is NULL), return the head itself as it is already the reversed list.

3. Recursive case: Call `reverseList` recursively on the next node (head->next) to reverse the remaining part of the list.

4. After the recursion returns, the next node (head->next) will be pointing to the last node of the reversed list. So, set its next pointer to the current head node to reverse the connection.

5. Set the next pointer of the current head to NULL to avoid forming a cycle.

6. Finally, return the next node as the new head of the reversed list.

Here is the implementation:

```cpp
#include<iostream>

struct Node {
    int data;
    Node* next;
};

Node* reverseList(Node* head) {
    // Base case: if the list is empty or has only one element
    if (head == NULL || head->next == NULL) {
        return head;
    }

    // Recursive case: reverse the remaining part of the list
    Node* nextNode = reverseList(head->next);

    // Reverse the connection
    head->next->next = head;

    // Set the next pointer of the current head to NULL
    head->next = NULL;

    // Return the new head of the reversed list
    return nextNode;
}

void printList(Node* head) {
    while (head != NULL) {
        std::cout << head->data << " ";
        head = head->next;
    }
    std::cout << std::endl;
}

int main() {
    // Create a sample linked list: 1 -> 2 -> 3 -> 4 -> 5
    Node* head = new Node();
    Node* second = new Node();
    Node* third = new Node();
    Node* fourth = new Node();
    Node* fifth = new Node();

    head->data = 1;
    head->next = second;

    second->data = 2;
    second->next = third;

    third->data = 3;
    third->next = fourth;

    fourth->data = 4;
    fourth->next = fifth;

    fifth->data = 5;
    fifth->next = NULL;

    std::cout << "Original list: ";
    printList(head);

    // Reverse the list
    head = reverseList(head);

    std::cout << "Reversed list: ";
    printList(head);

    // Deallocate memory
    delete head;
    delete second;
    delete third;
    delete fourth;
    delete fifth;

    return 0;
}
```

This code will output:

```
Original list: 1 2 3 4 5
Reversed list: 5 4 3 2 1
```

