```javascript
function getPrimes(n) {
  var primes = [];
  var i = 2;

  while (primes.length < n) {
    var isPrime = true;

    for (var j = 2; j <= Math.sqrt(i); j++) {
      if (i % j === 0) {
        isPrime = false;
        break;
      }
    }

    if (isPrime) {
      primes.push(i);
    }

    i++;
  }

  return primes;
}

// Example usage
