    char input[MAX_INPUT_LENGTH];
    int includeUpper = 1;
    int includeLower = 1;
    int includeDigits = 1;
    int totalSum = 0;

    printf("Enter a string (minimum length of 10 characters): ");
    fgets(input, sizeof(input), stdin);
    input[strcspn(input, "\n")] = '\0';

    while (strlen(input) < 10 || validateString(input) == 0) {
        printf("Invalid string! Please enter a valid string: ");
        fgets(input, sizeof(input), stdin);
        input[strcspn(input, "\n")] = '\0';
    }

    calculateASCII(input, &includeUpper, &includeLower, &includeDigits, &totalSum);
    printASCII(input, &includeUpper, &includeLower, &includeDigits, &totalSum);

    return 0;
}

int validateString(char* input) {
    for (int i = 0; input[i] != '\0'; i++) {
        if (!isalnum(input[i])) {
            return 0;
        }
    }
    return 1;
}

void calculateASCII(char* input, int* includeUpper, int* includeLower, int* includeDigits, int* totalSum) {
    for (int i = 0; input[i] != '\0'; i++) {
        if ((*includeUpper == 1 && isupper(input[i])) ||
            (*includeLower == 1 && islower(input[i])) ||
            (*includeDigits == 1 && isdigit(input[i]))) {
            *totalSum += (int)input[i];
        }
    }
}

void printASCII(char* input, int* includeUpper, int* includeLower, int* includeDigits, int* totalSum) {
    printf("ASCII values of all characters in the string \"%s\" are: ", input);
    for (int i = 0; input[i] != '\0'; i++) {
        if ((*includeUpper == 1 && isupper(input[i])) ||
            (*includeLower == 1 && islower(input[i])) ||
            (*includeDigits == 1 && isdigit(input[i]))) {
            printf("%d, ", (int)input[i]);
        }
    }
    printf("\nTotal sum of ASCII values: %d\n", *totalSum);
}

Here is an improved function that iterates through objects and arrays to determine the types of nested structures, and also checks if a value is an instance of a class:

```javascript
function discernDataType(value) {
  let output;

  // Check for null values
  if (value === null) {
    return "Null";
  }

  // Check for array values
  if (Array.isArray(value)) {
    output = "Array: [";
    for (let i = 0; i < value.length; ++i) {
      output += discernDataType(value[i]) + ', ';
    }
    output = output.slice(0, -2) + ']';
    return output;
  }

  // Check for object values
  if (typeof value === "object") {
    // Check if it's a custom built class instance
    if (value.constructor.name !== "Object") {
      return "Instance of " + value.constructor.name;
    }

    // Otherwise assume it's an object literal
    output = "Object: {";
    for (let key in value) {
      output += key + ": " + discernDataType(value[key]) + ', ';
    }
    output = output.slice(0, -2) + '}';
    return output;
  }

  // Check for function values
  if (typeof value === "function") {
    return "Function";
  }

  // Otherwise return the basic data type
  return typeof value;
}
```

