import java.util.Arrays;

public class RemoveDuplicates {
    public static void main(String[] args) {
        int[] array = {1, 2, 3, 2, 4, 5, 3, 6, 7, 6, 8, 9, 10, 11, 5};

        Arrays.sort(array); // Sort the array in ascending order

        int j = 0; // Index of the next element to be filled in the array

        for (int i = 0; i < array.length - 1; i++) {
            if (array[i] != array[i + 1]) {
                array[j] = array[i];
                j++;
            }
        }

        array[j] = array[array.length - 1]; // Fill the last element

        int[] result = Arrays.copyOf(array, j + 1); // Create a new array with the correct length

        System.out.println(Arrays.toString(result)); // Print the result
    }
}
