using System.Threading.Tasks;

public class HttpRequestHandler
{
    public async Task<HttpResponseMessage> MakeHttpRequestAsync(HttpClient client, HttpRequestMessage request, Func<HttpResponseMessage, Task> responseHandler, CancellationToken cancellationToken)
    {
        if (client == null)
        {
            throw new ArgumentNullException(nameof(client), "HttpClient cannot be null.");
        }

        if (request == null)
        {
            throw new ArgumentNullException(nameof(request), "HttpRequestMessage cannot be null.");
        }

        if (responseHandler == null)
        {
            throw new ArgumentNullException(nameof(responseHandler), "Response handler function cannot be null.");
        }

        if (cancellationToken.IsCancellationRequested)
        {
            throw new OperationCanceledException("The operation was canceled.");
        }

        try
        {
            HttpResponseMessage response = await client.SendAsync(request, cancellationToken);
            await responseHandler(response);
            return response;
        }
        catch (OperationCanceledException)
        {
            throw; // Re-throw the OperationCanceledException
        }
        catch (Exception ex)
        {
            // Handle other exceptions or log them
            throw new HttpRequestException("An error occurred while making the HTTP request.", ex);
        }
    }
}
