```python
from functools import reduce
from decimal import Decimal, getcontext

def flatten(lst):
    for x in lst:
        if isinstance(x, list):
            for y in flatten(x):
                yield y
        else:
            try:
                yield float(x)
            except (ValueError, TypeError):
                continue

def product(lst):
    getcontext().prec = 2
    return reduce(lambda x, y: Decimal(x) * Decimal(y), lst, 1)

def max_product_list(list_of_lists):
    max_product = float('-inf')
    max_lists = []
    for lst in list_of_lists:
        flat_list = list(flatten(lst))
        if flat_list:
            temp_product = float(product(flat_list))
            if temp_product > max_product:
                max_product = temp_product
                max_lists = [flat_list]
            elif temp_product == max_product:
                max_lists.append(flat_list)
    return max_product, max_lists
```
