        self.left = None
        self.right = None
        self.size = 1

class BST:
    def __init__(self):
        self.root = None

    def insert(self, city):
        self.root = self._insert(self.root, city)

    def _insert(self, node, city):
        if node is None:
            return Node(city)
        if city.population > node.city.population:
            node.right = self._insert(node.right, city)
        else:
            node.left = self._insert(node.left, city)
        node.size += 1
        return node

    def find_kth_largest(self, k):
        return self._find_kth_largest(self.root, k)

    def _find_kth_largest(self, node, k):
        if node is None:
            return None
        right_size = node.right.size if node.right else 0
        if k == right_size + 1:
            return node.city
        elif k <= right_size:
            return self._find_kth_largest(node.right, k)
        else:
            return self._find_kth_largest(node.left, k - right_size - 1)

    def traverse_in_order(self):
