        {
            des.Key = ASCIIEncoding.ASCII.GetBytes(sKey);
            des.IV = ASCIIEncoding.ASCII.GetBytes(sKey);

            using (FileStream fsInput = new FileStream(inputFile, FileMode.Open, FileAccess.Read))
