#include <comdef.h>
#include <Windows.h>
#include <tlhelp32.h>

class MemoryManager
{
private:
    DWORD _pId;
    HANDLE _pHandle;
    bool _isReady;

public:
    MemoryManager() : _pId(0), _pHandle(NULL), _isReady(false) {}

    ~MemoryManager()
    {
        if (_isReady)
        {
            CloseHandle(_pHandle);
        }
    }

    bool OpenProcess(const char* processName)
    {
        HANDLE hSnapshot = CreateToolhelp32Snapshot(TH32CS_SNAPPROCESS, 0);
        PROCESSENTRY32 pe32;
        pe32.dwSize = sizeof(PROCESSENTRY32);

        if (Process32First(hSnapshot, &pe32))
        {
            do
            {
                if (strcmp(pe32.szExeFile, processName) == 0)
                {
                    _pId = pe32.th32ProcessID;
                    _pHandle = OpenProcess(PROCESS_ALL_ACCESS, FALSE, _pId);
                    _isReady = true;
                    CloseHandle(hSnapshot);
                    return true;
                }
            } while (Process32Next(hSnapshot, &pe32));
        }

        CloseHandle(hSnapshot);
        return false;
    }

    bool ReadMemory(DWORD address, LPVOID buffer, SIZE_T size)
    {
        if (_isReady)
        {
            SIZE_T bytesRead;
            if (ReadProcessMemory(_pHandle, (LPCVOID)address, buffer, size, &bytesRead))
            {
                return true;
            }
        }
        return false;
    }

    bool WriteMemory(DWORD address, LPCVOID buffer, SIZE_T size)
    {
        if (_isReady)
        {
            SIZE_T bytesWritten;
            if (WriteProcessMemory(_pHandle, (LPVOID)address, buffer, size, &bytesWritten))
            {
                return true;
            }
        }
        return false;
    }

    void CloseProcess()
    {
        if (_isReady)
        {
            CloseHandle(_pHandle);
            _isReady = false;
        }
    }
};
