import argparse
import codecs

def encode_file(input_file, output_file, encoding):
    try:
        with open(input_file, 'r', encoding='utf-8') as file:
            content = file.read()
            encoded_content = codecs.encode(content, encoding)
            with open(output_file, 'wb') as output:
                output.write(encoded_content)
    except FileNotFoundError:
        print("Input file not found.")
    except Exception as e:
        print(f"An error occurred: {e}")

def decode_file(encoded_file, encoding):
    try:
        with open(encoded_file, 'rb') as file:
            encoded_content = file.read()
            decoded_content = codecs.decode(encoded_content, encoding)
            print(decoded_content)
    except FileNotFoundError:
        print("Encoded file not found.")
    except Exception as e:
        print(f"An error occurred: {e}")

if __name__ == "__main__":
    parser = argparse.ArgumentParser(description='File encoding and decoding')
    parser.add_argument('input_file', help='Input file path')
    parser.add_argument('output_file', help='Output file path')
    parser.add_argument('encoding', help='Encoding type')
    parser.add_argument('--decode', action='store_true', help='Decode the encoded file')

    args = parser.parse_args()

    if not args.decode:
        encode_file(args.input_file, args.output_file, args.encoding)
    else:
        decode_file(args.input_file, args.encoding)
