Here is a Java code snippet that swaps the values of two given strings without using a temporary variable:

```java
public class StringSwap {
    public static void main(String[] args) {
        String a = "hello";
        String b = "world";

        System.out.println("Before swapping:");
        System.out.println("a = " + a);
        System.out.println("b = " + b);

        swapStrings(a, b);

        System.out.println("After swapping:");
        System.out.println("a = " + a);
        System.out.println("b = " + b);
    }

    public static void swapStrings(String a, String b) {
        char[] aChars = a.toCharArray();
        char[] bChars = b.toCharArray();

        // Reverse the characters in string a
        for (int i = 0; i < aChars.length / 2; i++) {
            char temp = aChars[i];
            aChars[i] = aChars[aChars.length - 1 - i];
            aChars[aChars.length - 1 - i] = temp;
        }

        // Reverse the characters in string b
        for (int i = 0; i < bChars.length / 2; i++) {
            char temp = bChars[i];
            bChars[i] = bChars[bChars.length - 1 - i];
            bChars[bChars.length - 1 - i] = temp;
        }

        // Reverse the characters in string a again to restore the original order
        for (int i = 0; i < aChars.length / 2; i++) {
            char temp = aChars[i];
            aChars[i] = aChars[aChars.length - 1 - i];
            aChars[aChars.length - 1 - i] = temp;
        }

        // Reverse the characters in string b again to restore the original order
        for (int i = 0; i < bChars.length / 2; i++) {
            char temp = bChars[i];
            bChars[i] = bChars[bChars.length - 1 - i];
            bChars[bChars.length - 1 - i] = temp;
        }

        // Convert the character arrays back to strings
        a = new String(aChars);
        b = new String(bChars);
    }
}
```

