    int len = strlen(str);
    char* result = (char*)malloc((len + 1) * sizeof(char));
    int resultIndex = 0;

    for (int i = 0; i < len; i++) {
        // If the current character is lowercase and the previous character is uppercase, add an extra uppercase letter
        if (islower(str[i]) && isupper(str[i - 1])) {
