import java.util.Scanner;

public class RhombusStar {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter the number of rows for rhombus:");
        int rows = scanner.nextInt();
        printRhombus(rows);
        scanner.close();
    }

    private static void printRhombus(int n) {
        int i, j;
        for (i = 0; i < n; i++) {
            for (j = 0; j < n - i; j++)
                System.out.print(" ");
            for (j = 0; j < 2 * i + 1; j++)
                System.out.print("*");
            System.out.print("\n");
        }
        for (i = n - 2; i >= 0; i--) {
            for (j = 0; j < n - i; j++)
                System.out.print(" ");
            for (j = 0; j < 2 * i + 1; j++)
                System.out.print("*");
            System.out.print("\n");
        }
    }
}
```
